10→class FlowCallbackTest : TestBase() {
11→    @Test
12→    fun testClosedPrematurely() = runTest {
13→        val outerScope = this
14→        val flow = callbackFlow {
15→            // ~ callback-based API
16→            outerScope.launch(Job()) {
17→                expect(2)
18→                try {
19→                    send(1)
20→                    expectUnreached()
21→                } catch (e: IllegalStateException) {
22→                    expect(3)
23→                    assertTrue(e.message!!.contains("awaitClose"))
24→                }
25→            }
26→            expect(1)
27→        }
28→        try {
29→            flow.collect()
30→        } catch (e: IllegalStateException) {
31→            expect(4)
32→            assertTrue(e.message!!.contains("awaitClose"))
33→        }
34→        finish(5)
35→    }
36→
37→    @Test
38→    fun testNotClosedPrematurely() = runTest {
39→        val outerScope = this
40→        val flow = callbackFlow {
41→            // ~ callback-based API
42→            outerScope.launch(Job()) {
43→                expect(2)
44→                send(1)
45→                close()
46→            }
47→            expect(1)
48→            awaitClose()
49→        }
50→
51→        assertEquals(listOf(1), flow.toList())
52→        finish(3)
53→    }
54→}
